Here's a modern MSTest test class using both `DataRow` and `DynamicData` with ValueTuples:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator;

    public PriceCalculatorTests()
    {
        _calculator = new PriceCalculator();
    }

    // --- DataRow: inline values for CalculateTotal ---

    [TestMethod]
    [DataRow(10.00, 3, 30.00, DisplayName = "Simple multiplication")]
    [DataRow(0.00, 5, 0.00, DisplayName = "Zero price")]
    [DataRow(19.99, 0, 0.00, DisplayName = "Zero quantity")]
    [DataRow(9.99, 1, 9.99, DisplayName = "Single item")]
    [DataRow(5.50, 10, 55.00, DisplayName = "Ten items")]
    public void CalculateTotal_WithVariousInputs_ReturnsExpected(
        double price, int quantity, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)price, quantity);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- DynamicData with ValueTuples for ApplyDiscount ---

    [TestMethod]
    [DynamicData(nameof(DiscountTestData))]
    public void ApplyDiscount_WithVariousDiscounts_ReturnsExpected(
        decimal price, int discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, int discountPercent, decimal expected)> DiscountTestData =>
    [
        (100m, 10, 90m),
        (200m, 25, 150m),
        (50m, 0, 50m),
        (80m, 100, 0m),
        (0m, 50, 0m),
    ];

    // --- Edge case: invalid discount throws ---

    [TestMethod]
    [DataRow(-1)]
    [DataRow(101)]
    public void ApplyDiscount_InvalidPercent_ThrowsArgumentOutOfRange(int percent)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, percent));

        Assert.AreEqual("discountPercent", ex.ParamName);
    }
}
```

**Key points:**
- **`DataRow`** — best for simple inline primitive values (note: `decimal` literals aren't compile-time constants, so use `double` and cast)
- **`DynamicData` with ValueTuples** — preferred for complex/decimal data; gives type safety and named parameters (requires MSTest 3.7+)
- **`sealed` class**, constructor init, AAA pattern, and `Assert.ThrowsExactly` for exceptions
- `DisplayName` on `DataRow` improves test explorer readability

